class Solution:
    def findMin(self, nums: list[int]) -> int:
        l, r = 0, len(nums) - 1
        while l < r:
            m = (l + r) // 2
            if nums[m] > nums[r]:    # 中点比右端大 -> 最小值在右半 (m+1..r)
                l = m + 1
            else:                    # 中点 <= 右端 -> 最小值在左半(含 m)
                r = m
        return nums[l]
